SELECT a.id, a.name, a.item_code, a.item_group, a.step_maxgrade, a.standard_price,
       b.line_amount, b.line_mode
FROM pr_standard a
LEFT JOIN pr_standard_price b
    ON b.standard_id = a.id AND b.company_id = #{companyId} AND b.org_id = #{orgId}
       AND b.grade = 1 AND b.step_1_2 = 1
WHERE a.company_id = #{companyId}
  AND a.org_id = #{orgId}
  AND a.item_group = '5'
  AND a.item_code = '01'

SELECT a.id, a.name, a.item_code, a.item_group, a.step_maxgrade, a.standard_price,
       b.line_amount, b.line_mode
FROM pr_standard a
LEFT JOIN pr_standard_price b
    ON b.standard_id = a.id AND b.company_id = #{companyId} AND b.org_id = #{orgId}
       AND b.grade = 1 AND b.step_1_2 = 1
WHERE a.company_id = #{companyId}
  AND a.org_id = #{orgId}
  AND a.item_group = '5'
  AND a.item_code = '02'

SELECT a.id, a.name, a.item_code, a.item_group, a.step_maxgrade, a.standard_price,
       b.line_amount, b.line_mode
FROM pr_standard a
LEFT JOIN pr_standard_price b
    ON b.standard_id = a.id AND b.company_id = #{companyId} AND b.org_id = #{orgId}
       AND b.grade = 1 AND b.step_1_2 = 1
WHERE a.company_id = #{companyId}
  AND a.org_id = #{orgId}
  AND a.item_group = '6'

SELECT name FROM pr_standard
WHERE company_id = #{companyId}
  AND org_id = #{orgId}
  AND item_group = #{itemGroup}
  AND name = #{name}

    AND id != #{id}

SELECT COUNT(1) FROM pr_transaction_detail
WHERE meter_id = #{meterId}
  AND company_id = #{companyId}
  AND org_id = #{orgId}
  AND is_deleted = '0'
  AND DATE_FORMAT(record_time, '%Y-%m') = DATE_FORMAT(NOW(), '%Y-%m')

SELECT ROUND(IFNULL(SUM(receivable), '0'), 2) FROM pr_transaction_detail
WHERE meter_id = #{meterId}
  AND company_id = #{companyId}
  AND org_id = #{orgId}
  AND is_deleted = '0'
  AND DATE_FORMAT(record_time, '%Y-%m') = DATE_FORMAT(NOW(), '%Y-%m')

SELECT COUNT(1) FROM pr_transaction_detail
WHERE meter_id = #{meterId}
  AND company_id = #{companyId}
  AND org_id = #{orgId}
  AND is_deleted = '0'
  AND YEAR(record_time) = YEAR(NOW())
  AND QUARTER(record_time) = QUARTER(NOW())

SELECT ROUND(IFNULL(SUM(receivable), '0'), 2) FROM pr_transaction_detail
WHERE meter_id = #{meterId}
  AND company_id = #{companyId}
  AND org_id = #{orgId}
  AND is_deleted = '0'
  AND YEAR(record_time) = YEAR(NOW())
