SELECT b.*
FROM pr_standard a
LEFT JOIN pr_expense_item b
    ON a.company_id = b.company_id AND a.org_id = b.org_id
       AND a.item_group = b.item_group AND a.item_code = b.item_code
WHERE a.id = #{standardId}
  AND a.company_id = #{companyId}
  AND a.org_id = #{orgId}
